auto ast = parser.compilationUnit();
Obj::Mgr mgr;

asg::Ast2Asg ast2asg(mgr);
auto asg = ast2asg(ast->translationUnit());
mgr.mRoot = asg;
mgr.gc();

asg::Typing inferType(mgr);
inferType(asg);
mgr.gc();

asg::Asg2Json asg2json;
llvm::json::Value json = asg2json(asg);

